{
  "scripts": {
    "prebuild":   "npm run typecheck",     // runs before 'build'
    "build":      "vite build",
    "postbuild":  "node scripts/sizeCheck.js",  // runs after 'build' succeeds

    "pretest":    "npm run lint",          // lint before tests
    "test":       "vitest run",

    "preinstall": "node -e \"if(process.env.npm_execpath?.includes('pnpm')){process.exit(1)}\""
  }
}

{
  "scripts": {
    // Run both only if the first succeeds:
    "build":  "tsc && vite build",

    // Chain multiple npm run calls:
    "ci":     "npm run typecheck && npm run lint && npm run test && npm run build",

    // Ignore failure (useful for optional clean step):
    "clean":  "rm -rf dist || true",

    // Run scripts in parallel with & (Unix only):
    "watch":  "tsc --watch & vite"
  }
}

{
  "scripts": {
    // Inline env var (Unix syntax — breaks on Windows):
    "build:staging": "NODE_ENV=staging vite build",

    // Cross-platform env var with cross-env:
    "build:staging": "cross-env NODE_ENV=staging vite build"
  }
}

{
  "scripts": {
    // cross-env sets env vars cross-platform:
    "build":         "cross-env NODE_ENV=production vite build",
    "build:staging": "cross-env NODE_ENV=staging VITE_API=https://staging.api.com vite build",

    // rimraf is a cross-platform rm -rf:
    "clean":  "rimraf dist",
    "clean:all": "rimraf dist node_modules"
  }
}

// scripts/generate-icons.mjs
import { readdir, writeFile } from 'node:fs/promises';
import { join } from 'node:path';

const icons = await readdir('src/assets/icons');
const exports = icons
  .filter(f => f.endsWith('.svg'))
  .map(f => `export { ReactComponent as ${f.replace('.svg', '')} } from './${f}';`)
  .join('\n');

await writeFile('src/assets/icons/index.ts', exports);
console.log(`Generated exports for ${icons.length} icons`);

// scripts/check.mjs — shared script used by 'prebuild' and 'pretest'
const event = process.env.npm_lifecycle_event;

if (event === 'prebuild') {
  // stricter checks before a release build
  console.log('Running strict pre-build checks...');
  await runTypeCheck({ strict: true });
} else if (event === 'pretest') {
  // lighter checks before tests
  console.log('Running quick pre-test checks...');
  await runLint({ fix: false });
}

// package.json
{
  "scripts": {
    "prepare": "husky"   // runs after npm install — installs git hooks
  },
  "lint-staged": {
    "*.{ts,tsx}": ["eslint --fix", "prettier --write"],
    "*.{json,css,md}": ["prettier --write"]
  }
}

{
  "scripts": {
    // Development
    "dev":            "vite",
    "preview":        "vite preview",

    // Type checking
    "typecheck":      "tsc --noEmit",
    "typecheck:watch": "tsc --noEmit --watch",

    // Linting and formatting
    "lint":           "eslint src --ext .ts,.tsx --max-warnings 0",
    "lint:fix":       "eslint src --ext .ts,.tsx --fix",
    "format":         "prettier --write \"src/**/*.{ts,tsx,css,json}\"",
    "format:check":   "prettier --check \"src/**/*.{ts,tsx,css,json}\"",

    // Testing
    "test":           "vitest",
    "test:run":       "vitest run",
    "test:coverage":  "vitest run --coverage",

    // Building
    "prebuild":       "npm run typecheck",
    "build":          "vite build",
    "build:staging":  "cross-env VITE_ENV=staging vite build",

    // CI gate (run all checks in sequence)
    "ci":             "npm run typecheck && npm run lint && npm run format:check && npm run test:run && npm run build",

    // Utilities
    "clean":          "rimraf dist",
    "clean:all":      "rimraf dist node_modules",

    // Git hooks setup
    "prepare":        "husky"
  }
}

{
  "scripts": {
    // Start on a specific port:
    "dev":        "vite --port 3000",

    // Open browser automatically:
    "dev:open":   "vite --open",

    // Build with a custom output directory:
    "build":      "vite build --outDir build",

    // Build only if TypeScript is clean:
    "build:safe": "tsc --noEmit && vite build",

    // Preview the built output on port 4000:
    "preview":    "vite preview --port 4000 --host",

    // Build with bundle analysis:
    "analyze":    "VITE_VISUALIZE=true vite build"
  }
}

{
  "scripts": {
    // Interactive watch mode (re-runs on file changes):
    "test":            "vitest",

    // Run once and exit (for CI):
    "test:run":        "vitest run",

    // With coverage report:
    "test:coverage":   "vitest run --coverage",

    // With browser-based UI:
    "test:ui":         "vitest --ui",

    // Run only tests matching a pattern:
    "test:auth":       "vitest auth",

    // Typecheck test files too:
    "test:types":      "vitest typecheck"
  }
}

// Access in your React code:
const apiUrl = import.meta.env.VITE_API_URL;
const isProd = import.meta.env.PROD;    // built-in boolean
const isDev  = import.meta.env.DEV;     // built-in boolean
const mode   = import.meta.env.MODE;    // 'development' or 'production'

// TypeScript: declare custom env vars in vite-env.d.ts:
interface ImportMetaEnv {
  readonly VITE_API_URL: string;
  readonly VITE_APP_TITLE: string;
}
interface ImportMeta {
  readonly env: ImportMetaEnv;
}

{
  "scripts": {
    // Use npx to run a one-shot tool without installing:
    "storybook":    "npx storybook dev -p 6006",
    "icons:gen":    "npx @svgr/cli --typescript --out-dir src/icons src/assets/svg",

    // Or pin it as a devDependency and use directly:
    "storybook":    "storybook dev -p 6006"  // if 'storybook' is in devDependencies
  }
}
